#include <bits/stdc++.h>
using namespace std;
int day[13];
int main(){
    for(int i = 1; i <= 12; i++){
        if(i == 1 || i == 3 || i== 5 || i == 7 || i == 8 || i == 10 || i == 12) day[i] = 31;
        if(i == 4 || i == 6 || i == 9 || i == 11) day[i] = 30;
    }
    int y, m, d, h, k;
    cin >> y >> m >> d >> h >> k;
    if((y % 4 == 0 && y % 100 != 0) || (y % 400 == 0)){
    	day[2] = 29;
	}else{
		day[2] = 28;
	}
    if(h + k < 24){
        printf("%d %d %d %d\n", y, m, d, (h + k));
        return 0;
    }else{
    	if(d < day[m]){
    		printf("%d %d %d %d\n", y, m, (d + 1), (h + k - 24));
		}else{
			if(m < 12){
				printf("%d %d 1 %d\n", y, (m + 1), (h + k - 24));
			}else{
				printf("%d 1 1 %d\n", (y + 1), (h + k - 24));
			}
		}
	}
    return 0;
}
